content.title:
Run $src='D:\paper_reading\paper_reading\papers_sources\Research-Paper-Notes\CIF.md'; $note='D:\paper_reading\paper_reading\notes\CIF Continuous Integrate-and-Fire.md';
$srcLines=Get-Content -LiteralPath $src -Encoding utf8;
$noteLines=Get-Content -LiteralPath $note -Encoding utf8;
# remove obvious markdown noise for rough containment check
function Norm([string]$s){
  if($null -eq $s){return ''}
  $t=$s.Trim();
  if($t -eq ''){return ''}
  $t=$t -replace '\s+',' ';
  return $t
}
$noteSet = New-Object 'System.Collections.Generic.HashSet[string]'
foreach($l in $noteLines){$n=Norm $l; if($n -ne ''){$null=$noteSet.Add($n)}}
$missing = @()
foreach($l in $srcLines){
  $n=Norm $l
  if($n -eq ''){continue}
  if(-not $noteSet.Contains($n)){$missing += $n}
}
$uniqueMissing = $missing | Sort-Object -Unique
"SRC_NONEMPTY=" + (($srcLines | ForEach-Object {Norm $_} | Where-Object {$_ -ne ''}).Count)
"UNIQUE_MISSING=" + $uniqueMissing.Count
$uniqueMissing | Select-Object -First 80

