content.title:
Run $src='D:\paper_reading\paper_reading\papers_sources\Research-Paper-Notes\PanGu-π.md'; $dst='D:\paper_reading\paper_reading\notes\PanGu-pi Nonlinearity Compensation.md';
function GetRefs($p){
  $txt=Get-Content -LiteralPath $p -Encoding utf8 -Raw
  $refs=@()
  $m1=[regex]::Matches($txt,'!\[[^\]]*\]\(([^\)]+)\)')
  foreach($m in $m1){$refs += $m.Groups[1].Value}
  $m2=[regex]::Matches($txt,'!\[\[([^\]]+)\]\]')
  foreach($m in $m2){$refs += $m.Groups[1].Value}
  $m3=[regex]::Matches($txt,'<img\s+[^>]*src="([^"]+)"')
  foreach($m in $m3){$refs += $m.Groups[1].Value}
  return $refs | ForEach-Object {[System.IO.Path]::GetFileName($_)} | Sort-Object -Unique
}
$s=GetRefs $src; $d=GetRefs $dst;
'MISSING_BY_FILENAME:'; Compare-Object -ReferenceObject $s -DifferenceObject $d | Where-Object {$_.SideIndicator -eq '<='} | Select-Object -ExpandProperty InputObject;
'APPENDIX_CHECK:'; (Select-String -LiteralPath $dst -Pattern '原始笔记完整摘录|零遗漏校对|附：原始完整笔记内嵌' -Encoding utf8 | Measure-Object).Count

